from openai import OpenAI
client = OpenAI()

tools = [{
    'type': 'function',
    'function': {
        'name': 'get_weather',
        'description': '查询某城市天气',
        'parameters': {
            'type': 'object',
            'properties': {'city': {'type': 'string'}},
            'required': ['city']
        }
    }
}]

resp = client.chat.completions.create(
    model='gpt-4o',
    messages=[{'role': 'user', 'content': '北京今天天气如何？'}],
    tools=tools
)
# Agent 决定调用 get_weather(city='北京')
print(resp.choices[0].message.tool_calls)
